async (page) => {
  // Navigate south via western path to avoid Goblins, aim for beach south of wall complex
  const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 183, y: 210});
  await page.waitForTimeout(5000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  const nearbyItems = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return gs.nearby_entities.filter(e => e.type === 4 || e.name === 'Hammer' || e.name === 'hammer').slice(0, 5);
  });
  return JSON.stringify({pos, nearbyItems});
}

async (page) => {
  // Head south to the beach area - Crabs at y=214+
  const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 183, y: 215});
  await page.waitForTimeout(5000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const gs = JSON.parse(state);
  return JSON.stringify({
    pos: gs.player_position,
    hp: gs.player_stats.hp,
    itemDrops: gs.nearby_entities.filter(e => e.type === 4),
    allEntities: gs.nearby_entities.slice(0, 8).map(e => ({name: e.name, type: e.type, x: e.x, y: e.y, dist: e.distance}))
  });
}

async (page) => {
  // Try west approach - go far west first (x=165) then south to beach
  // Click entity by ID from nearby_entities
  const crabId = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const crab = gs.nearby_entities.find(e => e.name === 'Crab');
    return crab ? crab.id : null;
  });

  // Try clicking tile at Crab coordinates via __clickTile
  const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 174, y: 214});
  await page.waitForTimeout(6000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify({crabId, r: JSON.parse(r), pos});
}
